var selectedItem = selected;
var dropHandled = EventBus.RaiseArcDropRequested(
    this,
    selectedItem,
    m_entity,
    () =>
    {
        if (selectedItem)
            Destroy(selectedItem.gameObject);

        if (selected == selectedItem)
            selected = null;

        m_dropTime = Time.time;
    },
    SafeDeselect
);

if (dropHandled)
    return;
